// Tab 5: Readiness Assessment
// =============================================================================

function ReadinessView({ fonts }) {
  const { fontSans, fontSerif, fontMono } = fonts;
  const [answers, setAnswers] = useState({});
  const [schemeName, setSchemeName] = useState('NRES Brackley & Towcester NHC');

  const setAnswer = (qid, val) => setAnswers(prev => ({ ...prev, [qid]: val }));

  // Scoring
  const scores = READINESS_CRITERIA.map(crit => {
    const pts = crit.questions.reduce((sum, q) => sum + (answers[q.id] === 'yes' ? 2 : answers[q.id] === 'partial' ? 1 : 0), 0);
    const max = crit.questions.length * 2;
    const answered = crit.questions.every(q => answers[q.id]);
    const pct = max > 0 ? Math.round((pts / max) * 100) : 0;
    const rag = pct >= 70 ? 'green' : pct >= 40 ? 'amber' : 'red';
    return { ...crit, pts, max, pct, rag, answered };
  });
  const totalPts = scores.reduce((a, s) => a + s.pts, 0);
  const totalMax = scores.reduce((a, s) => a + s.max, 0);
  const totalAnswered = READINESS_CRITERIA.reduce((a, c) => a + c.questions.filter(q => answers[q.id]).length, 0);
  const totalQuestions = READINESS_CRITERIA.reduce((a, c) => a + c.questions.length, 0);
  const overallPct = totalMax > 0 ? Math.round((totalPts / totalMax) * 100) : 0;
  const overallRag = overallPct >= 70 ? 'green' : overallPct >= 40 ? 'amber' : 'red';
  const ragColor = { green: '#1D7A5E', amber: '#D4A017', red: '#C0433F' };
  const ragBg = { green: '#E8F4EE', amber: '#FDF7EA', red: '#FBEAE8' };

  const gaps = scores.flatMap(c =>
    c.questions.filter(q => answers[q.id] === 'no' || answers[q.id] === 'partial').map(q => ({
      criterion: c.short, question: q.text, severity: answers[q.id],
    }))
  );

  return (
    <>
      {/* Header row: scheme name + overall */}
      <section style={{ display: 'grid', gridTemplateColumns: '1.6fr 1fr', gap: 16 }}>
        <div style={panelStyle}>
          <label style={labelStyle}>Scheme name</label>
          <input
            type="text" value={schemeName} onChange={(e) => setSchemeName(e.target.value)}
            style={{
              width: '100%', fontSize: 18, ...fontSerif, fontWeight: 500,
              border: 'none', background: 'transparent', marginTop: 6, color: '#1A1F26',
              outline: 'none', padding: '2px 0',
            }}
          />
          <div style={{ fontSize: 12, color: '#8A9198', marginTop: 10 }}>
            {totalAnswered} of {totalQuestions} questions answered
            {' · '}
            <span style={{ color: '#005EB8' }}>{Math.round((totalAnswered / totalQuestions) * 100)}% complete</span>
          </div>
          <div style={{ marginTop: 8, height: 6, background: '#F0EBE1', borderRadius: 3, overflow: 'hidden' }}>
            <div style={{ height: '100%', width: `${(totalAnswered / totalQuestions) * 100}%`, background: '#005EB8', transition: 'width 0.3s' }} />
          </div>
        </div>
        <div style={{ ...panelStyle, background: ragBg[overallRag], borderColor: ragColor[overallRag], padding: '18px 22px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
            <div>
              <div style={{ fontSize: 11, letterSpacing: '0.08em', textTransform: 'uppercase', color: ragColor[overallRag], fontWeight: 600 }}>
                Overall readiness
              </div>
              <div style={{ ...fontSerif, fontSize: 38, fontWeight: 400, color: ragColor[overallRag], lineHeight: 1, marginTop: 6 }}>
                {overallPct}%
              </div>
              <div style={{ fontSize: 12, color: ragColor[overallRag], marginTop: 4, fontWeight: 500 }}>
                {overallRag === 'green' && 'Submission-ready'}
                {overallRag === 'amber' && 'Gaps to address'}
                {overallRag === 'red' && 'Significant work needed'}
              </div>
            </div>
            <div style={{ textAlign: 'right', fontSize: 11, color: ragColor[overallRag], opacity: 0.8 }}>
              <div>{totalPts} of {totalMax} pts</div>
            </div>
          </div>
        </div>
      </section>

      {/* Main: criteria questions + sidebar scorecard */}
      <section style={{ marginTop: 18, display: 'grid', gridTemplateColumns: '1.6fr 1fr', gap: 16, alignItems: 'start' }}>
        {/* Questions */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
          {scores.map((crit, idx) => (
            <div key={crit.id} style={{ ...panelStyle, padding: '20px 22px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline', marginBottom: 4 }}>
                <div style={{ display: 'flex', alignItems: 'baseline', gap: 10 }}>
                  <span style={{ ...fontMono, fontSize: 11, color: '#8A9198' }}>{String(idx + 1).padStart(2, '0')}</span>
                  <div style={{ ...fontSerif, fontSize: 17, fontWeight: 500 }}>{crit.name}</div>
                </div>
                {crit.answered && (
                  <span style={{ fontSize: 11, padding: '3px 10px', borderRadius: 999, background: ragBg[crit.rag], color: ragColor[crit.rag], fontWeight: 500 }}>
                    {crit.pct}%
                  </span>
                )}
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 14 }}>
                {crit.questions.map(q => (
                  <QuestionRow key={q.id} q={q} answer={answers[q.id]} onChange={(v) => setAnswer(q.id, v)} fontSans={fontSans} />
                ))}
              </div>
            </div>
          ))}
        </div>

        {/* Sidebar scorecard */}
        <aside style={{ position: 'sticky', top: 20, display: 'flex', flexDirection: 'column', gap: 14 }}>
          <div style={{ ...panelStyle, padding: '18px 20px' }}>
            <div style={{ ...fontSerif, fontSize: 15, fontWeight: 500, marginBottom: 12 }}>Criterion scorecard</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 9 }}>
              {scores.map((c, i) => (
                <div key={c.id} style={{ display: 'flex', alignItems: 'center', gap: 10, fontSize: 12 }}>
                  <div style={{ ...fontMono, fontSize: 10, color: '#B0B6BA', minWidth: 16 }}>{String(i + 1).padStart(2, '0')}</div>
                  <div style={{ flex: 1, color: '#3A4147', fontSize: 11.5 }}>{c.short}</div>
                  {c.answered ? (
                    <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                      <span style={{ ...fontMono, fontSize: 11, color: ragColor[c.rag], fontWeight: 500, minWidth: 28, textAlign: 'right' }}>
                        {c.pct}%
                      </span>
                      <div style={{ width: 8, height: 8, borderRadius: '50%', background: ragColor[c.rag] }} />
                    </div>
                  ) : (
                    <span style={{ fontSize: 10, color: '#B0B6BA' }}>—</span>
                  )}
                </div>
              ))}
            </div>
          </div>

          {gaps.length > 0 && (
            <div style={{ ...panelStyle, padding: '18px 20px', background: '#FBF8F1' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 10 }}>
                <AlertCircle size={14} color="#D4A017" />
                <div style={{ fontSize: 13, fontWeight: 500 }}>Gaps to address ({gaps.length})</div>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                {gaps.slice(0, 5).map((g, i) => (
                  <div key={i} style={{ fontSize: 11.5, lineHeight: 1.4 }}>
                    <div style={{ color: g.severity === 'no' ? '#C0433F' : '#D4A017', fontWeight: 500, marginBottom: 2 }}>
                      {g.criterion} {g.severity === 'no' ? '· missing' : '· partial'}
                    </div>
                    <div style={{ color: '#5C6770' }}>{g.question}</div>
                  </div>
                ))}
                {gaps.length > 5 && (
                  <div style={{ fontSize: 11, color: '#8A9198', paddingTop: 4 }}>+{gaps.length - 5} more in full report</div>
                )}
              </div>
            </div>
          )}

          <button style={{
            padding: '13px 16px', background: '#005EB8', color: '#FFF', border: 'none', borderRadius: 8,
            fontSize: 13, fontWeight: 500, cursor: 'pointer',
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, ...fontSans,
          }}>
            <Sparkles size={14} /> Generate submission narrative
          </button>
          <p style={{ fontSize: 11, color: '#8A9198', lineHeight: 1.5, margin: 0 }}>
            Produces a draft narrative per criterion, ready to paste into the NHS England 28 May 2026 pipeline template.
          </p>
        </aside>
      </section>
    </>
  );
}

function QuestionRow({ q, answer, onChange, fontSans }) {
  const options = [
    { k: 'yes', l: 'Yes', icon: Check, color: '#1D7A5E', bg: '#E8F4EE' },
    { k: 'partial', l: 'Partial', icon: Minus, color: '#D4A017', bg: '#FDF7EA' },
    { k: 'no', l: 'No', icon: X, color: '#C0433F', bg: '#FBEAE8' },
  ];
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '10px 0', borderTop: '1px solid #F4EFE3' }}>
      <div style={{ flex: 1, fontSize: 13, color: '#3A4147', lineHeight: 1.45 }}>{q.text}</div>
      <div style={{ display: 'flex', gap: 4 }}>
        {options.map(o => {
          const active = answer === o.k;
          const Icon = o.icon;
          return (
            <button key={o.k} onClick={() => onChange(o.k)}
              style={{
                display: 'inline-flex', alignItems: 'center', gap: 5,
                padding: '6px 11px', fontSize: 11.5, fontWeight: 500,
                background: active ? o.bg : '#FFFFFF',
                color: active ? o.color : '#8A9198',
                border: `1px solid ${active ? o.color : '#E5DED1'}`,
                borderRadius: 6, cursor: 'pointer', ...fontSans,
                transition: 'all 0.15s',
              }}
            >
              <Icon size={11} strokeWidth={2.5} />
              {o.l}
            </button>
          );
        })}
      </div>
    </div>
  );
}

// =============================================================================
// Shared components & styles
// =============================================================================

function SegmentedControl({ options, value, onChange, fontSans }) {
  return (
    <div style={{ display: 'flex', background: '#F0EBE1', borderRadius: 8, padding: 3, gap: 2 }}>
      {options.map(o => (
        <button key={o.k} onClick={() => onChange(o.k)}
          style={{
            flex: 1, padding: '9px 8px', fontSize: 13, fontWeight: 500,
            background: value === o.k ? '#FFFFFF' : 'transparent',
            color: value === o.k ? '#1A1F26' : '#6A7278',
            border: 'none', borderRadius: 6, cursor: 'pointer',
            boxShadow: value === o.k ? '0 1px 2px rgba(0,0,0,0.05)' : 'none',
            transition: 'all 0.15s', ...fontSans,
          }}>
          {o.l}{o.sub && <span style={{ marginLeft: 5, fontSize: 11, color: '#8A9198' }}>{o.sub}</span>}
        </button>
      ))}
    </div>
  );
}

function MetricCard({ label, value, unit, sub, accent, fontMono }) {
  return (
    <div style={{ background: '#FFFFFF', border: '1px solid #E5DED1', borderRadius: 10, padding: '16px 18px' }}>
      <div style={{ fontSize: 11, letterSpacing: '0.08em', textTransform: 'uppercase', color: '#8A9198', fontWeight: 500 }}>{label}</div>
      <div style={{ marginTop: 8, display: 'flex', alignItems: 'baseline', gap: 4 }}>
        <span style={{ ...fontMono, fontSize: 26, fontWeight: 500, color: accent, letterSpacing: '-0.02em' }}>{value}</span>
        {unit && <span style={{ ...fontMono, fontSize: 14, color: '#8A9198' }}>{unit}</span>}
      </div>
      <div style={{ fontSize: 11, color: '#6A7278', marginTop: 6 }}>{sub}</div>
    </div>
  );
}

function ZonePanel({ config, scaled, scale, fonts }) {
  const { fontSerif, fontMono } = fonts;
  return (
    <div style={{ ...panelStyle, padding: '20px 20px 14px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div>
          <div style={{ ...fontSerif, fontSize: 18, fontWeight: 500 }}>Zone breakdown</div>
          <div style={{ fontSize: 12, color: '#8A9198' }}>Net departmental m² by functional zone</div>
        </div>
      </div>
      <div style={{ height: 200, margin: '8px 0 12px', position: 'relative' }}>
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie data={config.zones} innerRadius={56} outerRadius={88} paddingAngle={1} dataKey="value" stroke="#F7F4EE" strokeWidth={2}>
              {config.zones.map((z, i) => <Cell key={i} fill={ZONE_COLORS[z.name] || '#999'} />)}
            </Pie>
          </PieChart>
        </ResponsiveContainer>
        <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%,-50%)', textAlign: 'center', pointerEvents: 'none' }}>
          <div style={{ ...fontMono, fontSize: 22, fontWeight: 500 }}>{scaled.nda.toLocaleString()}</div>
          <div style={{ fontSize: 10, color: '#8A9198', letterSpacing: '0.08em', textTransform: 'uppercase' }}>NDA m²</div>
        </div>
      </div>
      <div style={{ display: 'grid', gap: 7, paddingTop: 10, borderTop: '1px solid #F0EBE1' }}>
        {config.zones.map((z, i) => {
          const pct = Math.round((z.value / config.nda) * 100);
          return (
            <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 10, fontSize: 12 }}>
              <div style={{ width: 10, height: 10, borderRadius: 2, background: ZONE_COLORS[z.name] || '#999' }} />
              <div style={{ flex: 1, color: '#3A4147' }}>{z.name}</div>
              <div style={{ ...fontMono, color: '#1A1F26', fontWeight: 500 }}>{Math.round(z.value * scale).toLocaleString()} m²</div>
              <div style={{ color: '#8A9198', fontSize: 11, minWidth: 30, textAlign: 'right' }}>{pct}%</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

const panelStyle = { background: '#FFFFFF', border: '1px solid #E5DED1', borderRadius: 10, padding: '16px 18px' };
const labelStyle = { display: 'block', fontSize: 11, letterSpacing: '0.08em', textTransform: 'uppercase', color: '#8A9198', fontWeight: 500, marginBottom: 10 };
const ghostBtn = { display: 'inline-flex', alignItems: 'center', gap: 6, padding: '8px 14px', fontSize: 12, fontWeight: 500, background: '#FFFFFF', border: '1px solid #E5DED1', borderRadius: 8, color: '#3A4147', cursor: 'pointer', fontFamily: "'Hanken Grotesk', sans-serif" };
const primaryBtn = { display: 'inline-flex', alignItems: 'center', gap: 6, padding: '8px 14px', fontSize: 12, fontWeight: 500, background: '#005EB8', color: '#FFFFFF', border: 'none', borderRadius: 8, cursor: 'pointer', fontFamily: "'Hanken Grotesk', sans-serif" };
const iconBtn = { display: 'inline-flex', alignItems: 'center', justifyContent: 'center', gap: 4, width: 30, height: 30, padding: 0, background: '#FFFFFF', border: '1px solid #E5DED1', borderRadius: 6, color: '#3A4147', cursor: 'pointer', fontFamily: "'Hanken Grotesk', sans-serif", fontWeight: 500 };
const darkIconBtn = { display: 'inline-flex', alignItems: 'center', justifyContent: 'center', gap: 4, width: 32, height: 32, padding: 0, background: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.18)', borderRadius: 6, color: '#F7F4EE', cursor: 'pointer', fontFamily: "'Hanken Grotesk', sans-serif", fontWeight: 500 };
const thStyle = { textAlign: 'left', fontSize: 11, letterSpacing: '0.05em', textTransform: 'uppercase', color: '#8A9198', fontWeight: 500, padding: '10px 8px' };
const tdStyle = { padding: '11px 8px', color: '#3A4147', fontSize: 13 };


